1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	const COMPONENT_BASE = 25;
4	const COMPONENT_BLOCK_BASE = 60;
5	const BLOCK_SIZE = 3;
6	
7	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
8	
9	const BASE_PREMIUM: Record<string, number> = {
10	  sword: 100,
11	  amulet: 60,
12	  staff: 80,
13	  potion: 40,
14	};
15	
16	type Item = { type: string };
17	type QuoteStep = { op: "quote"; items: Item[] };
18	type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
19	
20	const isComponent = (item: Item) => COMPONENT_TYPES.has(item.type);
21	
22	const componentBase = (items: Item[]): number => {
23	  const counts: Record<string, number> = {};
24	  for (const item of items) counts[item.type] = (counts[item.type] ?? 0) + 1;
25	  let total = 0;
26	  for (const count of Object.values(counts)) {
27	    const blocks = Math.floor(count / BLOCK_SIZE);
28	    const remainder = count % BLOCK_SIZE;
29	    total += blocks * COMPONENT_BLOCK_BASE + remainder * COMPONENT_BASE;
30	  }
31	  return total;
32	};
33	
34	const quotePremium = (items: Item[]): number => {
35	  const components = items.filter(isComponent);
36	  const mains = items.filter((i) => !isComponent(i));
37	  const base = mains.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0) + componentBase(components);
38	  const firstInsurance = base * FIRST_INSURANCE_RATE;
39	  return base + firstInsurance + PROCESSING_FEE;
40	};
41	
42	export const runScenario = (scenario: Scenario): { results: Array<{ premium: number }> } => ({
43	  results: scenario.steps.map((step) => ({ premium: quotePremium(step.items) })),
44	});
